  es: { home: ["inicio", "ir a inicio"], addEntry: ["anadir entrada", "nueva entrada"], save: ["guardar"], cancel: ["cancelar", "cerrar"], stop: ["dejar de escuchar", "detener"], read: ["leer", "leer en voz alta"] },
  pt: { home: ["inicio", "ir para inicio"], addEntry: ["adicionar item", "novo item"], save: ["salvar"], cancel: ["cancelar", "fechar"], stop: ["parar de ouvir", "parar"], read: ["ler", "ler em voz alta"] },
  fr: { home: ["accueil", "aller a l'accueil"], addEntry: ["ajouter une entree", "nouvelle entree"], save: ["enregistrer"], cancel: ["annuler", "fermer"], stop: ["arreter d'ecouter", "arreter"], read: ["lire", "lire a voix haute"] },
