function normalizeVoiceText(str) {
  return str.normalize("NFD").replace(/[̀-ͯ]/g, "").toLowerCase().trim().replace(/[.,!?]/g, "");
}

// ---------- Language state + lookup helpers ----------
function getLang() {
  return localStorage.getItem("notyet_lang") || "en";
}
function setLangStorage(code) {
  localStorage.setItem("notyet_lang", code);
}
function t(path) {
  const lang = getLang();
  const dict = TRANSLATIONS[lang] || TRANSLATIONS.en;
  const fallback = TRANSLATIONS.en;
  const parts = path.split(".");
  let node = dict, fnode = fallback;
  for (const p of parts) {
    node = node && node[p];
    fnode = fnode && fnode[p];
  }
  return (node !== undefined ? node : fnode) || path;
}
function tDivision(key, field) {
  return t(`divisions.${key}.${field}`);
}
